'use client';
import Image from 'next/image';
import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';
import { MapPin, Calendar } from 'lucide-react';

const slides = [
  {
    src: '/images/gus_market.png',
    title: 'Фермерские продукты',
  },
  {
    src: '/images/cheese.jpg',
    title: 'Крафтовые сыры',
  },
  {
    src: '/images/bread.jpg',
    title: 'Свежий хлеб',
  },
  {
    src: '/images/vegetables.jpg',
    title: 'Овощи и зелень',
  },
];

const Hero = () => {
  const [index, setIndex] = useState(0);

  // Автопрокрутка
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % slides.length);
    }, 4500);

    return () => clearInterval(interval);
  }, []);

  return (
    <section className="relative min-h-screen pt-24 pb-12 overflow-hidden flex items-center bg-[#FAF6EE]">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,_#E8F0E0_0%,_transparent_40%),radial-gradient(circle_at_bottom_left,_#F5EBD7_0%,_transparent_40%)]" />

      <div className="container mx-auto px-6 max-w-7xl grid lg:grid-cols-2 gap-16 items-center relative z-10">

        {/* ЛЕВАЯ ЧАСТЬ */}
        <div>
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="text-green-dark text-6xl md:text-8xl mb-6 font-display"
          >
            Гусь Маркет
          </motion.h1>

          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="font-display italic text-3xl text-green-main mb-6"
          >
            Больше, чем фермерский рынок
          </motion.p>

          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            className="text-text-medium text-lg max-w-lg mb-12 leading-relaxed opacity-80"
          >
           Мы не просто торговые места, а живая площадка, которая объединяет фермеров и локальных производителей в одном пространстве. Мы делаем качественные фермерские продукты доступными для каждого, поддерживаем и развиваем локальное производство и бережно относимся к тому, что делает каждого фермера и его продукт по-настоящему уникальными.
          </motion.p>

          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.5 }}
            className="bg-white/60 backdrop-blur-xl p-5 rounded-3xl shadow flex items-center gap-5 mb-10 max-w-md border border-white/80"
          >
            <div className="w-14 h-14 bg-[#E8F0E0] rounded-2xl flex items-center justify-center">
              <Calendar />
            </div>
            <p className="font-bold text-green-dark text-xl">
              Пт, Сб, Вс: 12:00 – 20:00
            </p>
          </motion.div>

          <motion.a
            whileHover={{ y: -3 }}
            href="https://yandex.by/maps/"
            target="_blank"
            className="inline-flex items-center gap-2 bg-green-main text-white px-10 py-5 rounded-2xl font-bold shadow-lg hover:bg-green-dark transition-all"
          >
            <MapPin size={20} />
            Найти на карте
          </motion.a>
        </div>

        {/* ПРАВАЯ ЧАСТЬ — КАРУСЕЛЬ */}
        {/* ПРАВАЯ ЧАСТЬ — КАРУСЕЛЬ */}
<div className="relative h-[650px] flex items-center justify-center">
  <div className="absolute w-[90%] h-[90%] bg-[#F5EBD7]/50 rounded-[4rem]" />

  <div className="relative w-full max-w-[480px] h-[480px] md:h-[550px] overflow-hidden z-10 rounded-[3rem]">
    <AnimatePresence mode="wait">
      <motion.div
        key={index}
        initial={{ opacity: 0, x: 80 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: -80 }}
        transition={{ duration: 0.6, ease: 'easeInOut' }}
        className="absolute inset-0"
      >
        <Image
          src={slides[index].src}
          alt={slides[index].title}
          fill
          className="object-cover rounded-[3rem]"
          priority
        />
      </motion.div>
    </AnimatePresence>
  </div>

  {/* Индикаторы */}
  <div className="absolute bottom-10 flex gap-3 z-20">
    {slides.map((_, i) => (
      <button
        key={i}
        onClick={() => setIndex(i)}
        className={`w-3 h-3 rounded-full transition-all ${
          i === index ? 'bg-green-main scale-125' : 'bg-green-main/30'
        }`}
      />
    ))}
  </div>
</div>

      </div>
    </section>
  );
};

export default Hero;
